INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", "リリ", 1, 321, 125801, 1, 0, 1, 24001, 2, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", "クリア", 1, 322, 126001, 1, 0, 2, 24001, 2, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("んーと。\nこれ、あげる。\nはい", "プレシア", 1, 323, 126101, 1, 0, 3, 24001, 2, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", "リリ", 2, 324, 125801, 1, 0, 4, 24001, 2, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", "クリア", 2, 325, 126001, 1, 0, 5, 24001, 2, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("お兄。\nきてくれて、うれしい", "プレシア", 2, 326, 126101, 1, 0, 6, 24001, 2, 40011);
